1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	} as const;
11	
12	type ItemType = keyof typeof BASE_PREMIUM;
13	type Item = { type: ItemType };
14	type Step = { op: "quote"; items: Array<Item> };
15	type Scenario = {
16	  customer: { yearsWithMHPCO: number };
17	  steps: Array<Step>;
18	};
19	
20	const itemPremium = (item: Item): number => {
21	  const base = BASE_PREMIUM[item.type];
22	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
23	  return base + firstInsuranceSurcharge;
24	};
25	
26	const sumItemPremiums = (items: Array<Item>): number =>
27	  items.reduce((total, item) => total + itemPremium(item), 0);
28	
29	const quotePremium = ({ items }: Step): number =>
30	  Math.ceil(sumItemPremiums(items) + PROCESSING_FEE);
31	
32	export const runScenario = (scenario: unknown): unknown => {
33	  const { steps } = scenario as Scenario;
34	  return {
35	    results: steps.map((step) => ({ premium: quotePremium(step) })),
36	  };
37	};
